# include<bits/stdc++.h>
using namespace std;

int main()
{
    int t;
    cin >> t;
    while (t--)
    {
        int n, c, d;
        cin >> n >> c >> d;
        vector<vector<int>> data(n, vector<int>(3));
        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < 3; j++)
            {
                cin >> data[i][j];
            }
        }
        int fwcp = -1; // fwcp means fountain with coin purchase
        int fwdp = -1; // fwdp means fountain with diamond purchase
        for (int i = 0; i < n; i++)
        {
            int prevBeautywcp = 0; // wcp means with coin purchase
            int prevBeautywdp = 0; // wdp means with diamond purchase
            if (data[i][2] == 0)
            {
                int coinsRequired = data[i][1];
                if (coinsRequired <= c)
                {
                    int getBeauty = data[i][0];
                    if (getBeauty > prevBeautywcp)
                    {
                        prevBeautywcp = getBeauty;
                        fwcp = i;
                    }
                }
            }
            else
            {
                int diamondsRequired = data[i][1];
                if (diamondsRequired <= d)
                {
                    int getBeauty = data[i][0];
                    if (getBeauty > prevBeautywdp)
                    {
                        prevBeautywdp = getBeauty;
                        fwdp = i;
                    }
                }
            }
        }
        if (fwdp == -1 || fwcp == -1)
            cout << 0 << endl;
        else
            cout << "select fountain number" << fwcp + 1 << "and" << fwdp + 1 << endl;
    }
}
